def generar_contrato(brief_cliente):
    requisitos = pedir_a_claude(f"Extraé los requisitos clave de: {brief_cliente}")

    if "falta" in requisitos.lower():  # gate
        return {"error": "requisitos incompletos, pedir más info al cliente"}

    borrador = pedir_a_claude(f"Redactá un borrador con estos requisitos: {requisitos}")
    version_final = pedir_a_claude(f"Revisá y pulí el lenguaje legal de: {borrador}")
    return {"contrato": version_final}

PROMPTS_POR_CATEGORIA = {
    "tecnico": ("claude-opus-4-8", "Sos soporte técnico nivel 2..."),
    "facturacion": ("claude-sonnet-4-6", "Sos soporte de facturación..."),
    "faq": ("claude-haiku-4-5-20251001", "Respondé preguntas frecuentes brevemente..."),
}

def enrutar_y_responder(mensaje):
    # modelo barato para clasificar
    categoria = pedir_a_claude(
        f"Clasificá en tecnico/facturacion/faq (una palabra): {mensaje}",
        modelo="claude-haiku-4-5-20251001",
    ).strip()

    modelo, system_prompt = PROMPTS_POR_CATEGORIA.get(categoria, PROMPTS_POR_CATEGORIA["faq"])
    return pedir_a_claude(mensaje, modelo=modelo, system=system_prompt)

def generar_con_evaluacion(tarea, criterios, max_intentos=3):
    feedback = ""
    for intento in range(max_intentos):
        borrador = pedir_a_claude(f"{tarea}\n\nFeedback de la iteración anterior: {feedback}")
        evaluacion = pedir_a_claude(
            f"Evaluá si este texto cumple estos criterios: {criterios}\n\nTexto: {borrador}\n\n"
            "Si cumple todo, respondé exactamente 'OK'. Si no, devolvé feedback específico y accionable."
        )
        if evaluacion.strip() == "OK":
            return borrador
        feedback = evaluacion
    return borrador  # se devuelve el último intento aunque no haya aprobado

tool_definir_subtareas = {
    "name": "definir_subtareas",
    "description": "Define en qué subtareas independientes dividir un trabajo de investigación",
    "input_schema": {
        "type": "object",
        "properties": {"subtareas": {"type": "array", "items": {"type": "string"}}},
        "required": ["subtareas"],
    },
}

def investigar(pregunta_compleja):
    # orquestador decide la división
    plan = client.messages.create(
        model="claude-opus-4-8", max_tokens=400,
        tools=[tool_definir_subtareas],
        tool_choice={"type": "tool", "name": "definir_subtareas"},
        messages=[{"role": "user", "content": f"Dividí en 2 a 4 subtareas independientes: {pregunta_compleja}"}],
    )
    subtareas = plan.content[0].input["subtareas"]

    resultados = asyncio.run(resolver_en_paralelo(subtareas))  # workers en paralelo

    return pedir_a_claude(f"Sintetizá estos hallazgos en una respuesta coherente:\n{resultados}")

def agente(objetivo, tools, max_iteraciones=8):
    mensajes = [{"role": "user", "content": objetivo}]

    for i in range(max_iteraciones):
        response = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=1500, tools=tools, messages=mensajes
        )
        mensajes.append({"role": "assistant", "content": response.content})

        if response.stop_reason != "tool_use":
            return response  # el agente considera la tarea terminada

        resultados = ejecutar_y_recolectar_tools(response.content)
        mensajes.append({"role": "user", "content": resultados})

    raise RuntimeError("el agente no convergió dentro del límite de iteraciones")

def compactar_si_hace_falta(mensajes, umbral_tokens=50000, conservar_ultimos=4):
    if estimar_tokens(mensajes) < umbral_tokens:
        return mensajes

    historial_viejo = mensajes[:-conservar_ultimos]
    resumen = pedir_a_claude(
        f"Resumí en pocos párrafos lo relevante de esto para continuar la tarea:\n{historial_viejo}"
    )
    return [
        {"role": "user", "content": f"Resumen de lo actuado hasta ahora:\n{resumen}"}
    ] + mensajes[-conservar_ultimos:]

import logging

ACCIONES_QUE_REQUIEREN_APROBACION = {"enviar_email", "cobrar_tarjeta", "borrar_registro"}

def ejecutar_con_aprobacion(bloque_tool_use):
    if bloque_tool_use.name in ACCIONES_QUE_REQUIEREN_APROBACION:
        aprobado = input(f"¿Aprobás ejecutar {bloque_tool_use.name} con {bloque_tool_use.input}? (s/n) ")
        if aprobado.lower() != "s":
            return "Acción cancelada por el usuario"
    return ejecutar_tool(bloque_tool_use.name, bloque_tool_use.input)

# logging de cada paso para depurar por qué el agente tomó un camino
logging.basicConfig(level=logging.INFO)

def agente_con_logging(objetivo, tools, max_iteraciones=8):
    mensajes = [{"role": "user", "content": objetivo}]
    for i in range(max_iteraciones):
        response = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=1500, tools=tools, messages=mensajes
        )
        logging.info(
            "iteración=%d stop_reason=%s tokens_salida=%d",
            i, response.stop_reason, response.usage.output_tokens,
        )
        for bloque in response.content:
            if bloque.type == "tool_use":
                logging.info("tool=%s input=%s", bloque.name, bloque.input)
        mensajes.append({"role": "assistant", "content": response.content})
        if response.stop_reason != "tool_use":
            return response
        resultados = ejecutar_y_recolectar_tools(response.content)
        mensajes.append({"role": "user", "content": resultados})
